export function insertHairSVG(svg, svgStr, hC, hD, uid) {
  const g = document.createElementNS(NS, 'g');
  svg.appendChild(g);
  const pfx = uid + Math.random().toString(36).slice(2,6);
  let s = svgStr
    .replace(/id="([^"]+)"/g, (_, i) => `id="${pfx}${i}"`)
    .replace(/url\(#([^)]+)\)/g, (_, i) => `url(#${pfx}${i})`)
    .replace(/xlink:href="#([^"]+)"/g, (_, i) => `href="#${pfx}${i}"`)
    .replace(/(?<!xlink:)href="#([^"]+)"/g, (_, i) => `href="#${pfx}${i}"`)
    .replace(/#784421/gi, hC)
    .replace(/#784133/gi, hC)
    .replace(/#724133/gi, hC)
    .replace(/stroke="#000000"/g, `stroke="${hD}"`)
    .replace(/stroke:#000000/g, `stroke:${hD}`);
  g.innerHTML = s;
  return g;
}

